// ServerInterface represents all server handlers.
type ServerInterface interface {
	// Health probe (root).
	// (GET /)
	GetRoot(c *gin.Context, params GetRootParams)
	// Fetch a captcha image, identified by URL-safe Base64.
	// (GET /captcha/{path})
	GetCaptcha(c *gin.Context, path string)
	// Paginated comments for a topic.
	// (GET /comments/{id})
	GetCommentsPage(c *gin.Context, id string, params GetCommentsPageParams)
	// Submit a comment on a topic.
	// (POST /comments/{id}/add)
	PostComment(c *gin.Context, id string, params PostCommentParams)
	// Download .torrent file (binary).
	// (GET /download/{id})
	GetDownload(c *gin.Context, id string, params GetDownloadParams)
	// User's favorited topics.
	// (GET /favorites)
	GetFavorites(c *gin.Context, params GetFavoritesParams)
	// Add a topic to the user's favorites.
	// (POST /favorites/add/{id})
	PostFavoritesAdd(c *gin.Context, id string, params PostFavoritesAddParams)
	// Remove a topic from the user's favorites.
	// (POST /favorites/remove/{id})
	PostFavoritesRemove(c *gin.Context, id string, params PostFavoritesRemoveParams)
	// Top-level forum category tree.
	// (GET /forum)
	GetForum(c *gin.Context, params GetForumParams)
	// Paginated category page (subforums and torrent listings).
	// (GET /forum/{id})
	GetCategoryPage(c *gin.Context, id string, params GetCategoryPageParams)
	// Health probe (alias of `/`).
	// (GET /index)
	GetIndex(c *gin.Context, params GetIndexParams)
	// Log in to rutracker; returns an AuthResponseDto.
	// (POST /login)
	PostLogin(c *gin.Context)
	// Search torrents by query, category, author, and time period.
	// (GET /search)
	GetSearch(c *gin.Context, params GetSearchParams)
	// Topic page (legacy ForumTopicDto polymorphic shape).
	// (GET /topic/{id})
	GetTopic(c *gin.Context, id string, params GetTopicParams)
	// Topic page (modern TopicPageDto shape).
	// (GET /topic2/{id})
	GetTopicPage(c *gin.Context, id string, params GetTopicPageParams)
	// Torrent metadata (TorrentDto).
	// (GET /torrent/{id})
	GetTorrent(c *gin.Context, id string, params GetTorrentParams)
}

