// GinServerOptions provides options for the Gin server.
type GinServerOptions struct {
	BaseURL      string
	Middlewares  []MiddlewareFunc
	ErrorHandler func(*gin.Context, error, int)
}

// RegisterHandlers creates http.Handler with routing matching OpenAPI spec.
func RegisterHandlers(router gin.IRouter, si ServerInterface) {
	RegisterHandlersWithOptions(router, si, GinServerOptions{})
}

// RegisterHandlersWithOptions creates http.Handler with additional options
func RegisterHandlersWithOptions(router gin.IRouter, si ServerInterface, options GinServerOptions) {
	errorHandler := options.ErrorHandler
	if errorHandler == nil {
		errorHandler = func(c *gin.Context, err error, statusCode int) {
			c.JSON(statusCode, gin.H{"msg": err.Error()})
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandler:       errorHandler,
	}

	router.GET(options.BaseURL+"/", wrapper.GetRoot)
	router.GET(options.BaseURL+"/captcha/:path", wrapper.GetCaptcha)
	router.GET(options.BaseURL+"/comments/:id", wrapper.GetCommentsPage)
	router.POST(options.BaseURL+"/comments/:id/add", wrapper.PostComment)
	router.GET(options.BaseURL+"/download/:id", wrapper.GetDownload)
	router.GET(options.BaseURL+"/favorites", wrapper.GetFavorites)
	router.POST(options.BaseURL+"/favorites/add/:id", wrapper.PostFavoritesAdd)
	router.POST(options.BaseURL+"/favorites/remove/:id", wrapper.PostFavoritesRemove)
	router.GET(options.BaseURL+"/forum", wrapper.GetForum)
	router.GET(options.BaseURL+"/forum/:id", wrapper.GetCategoryPage)
	router.GET(options.BaseURL+"/index", wrapper.GetIndex)
	router.POST(options.BaseURL+"/login", wrapper.PostLogin)
	router.GET(options.BaseURL+"/search", wrapper.GetSearch)
	router.GET(options.BaseURL+"/topic/:id", wrapper.GetTopic)
	router.GET(options.BaseURL+"/topic2/:id", wrapper.GetTopicPage)
	router.GET(options.BaseURL+"/torrent/:id", wrapper.GetTorrent)
}

